var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"소용없습니다.","JPN":"無駄です。","ENG":"Not a chance!","TWN":"沒用的。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아쉽네. 방금 건 회심의 한 발이었는데 말이지.","JPN":"残念だな。今のは会心の一発だったのに。","ENG":"Darn, that was my best shot.","TWN":"真可惜，剛才那一箭我很滿意說。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"화살로 절 이길 수는 없습니다.","JPN":"矢では私に勝つことはできません。","ENG":"You cannot beat me with your bow.","TWN":"你用弓箭是打不贏我的。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그러니 포기하십시오. 이번 일에 대한 책임은 당주님을 데려온 뒤에 추궁하도록 하죠.","JPN":"ですので諦めてください。\\n今回の件は当主を連れ戻した後に追及することにしましょう。","ENG":"Surrender now. You will be questioned after I bring Lady Nanahara back.","TWN":"你還是放棄吧。等我把堂主帶回來後再向你究責。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"맞아. 내 실력으로는 널 못 이겨.","JPN":"そうだよ。確かに僕の実力じゃ君には勝てない。","ENG":"You’re right. I can’t beat you with my skills.","TWN":"沒錯，我確實打不贏你。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그래도 막을 거야.","JPN":"だけど僕は諦めないよ。","ENG":"But still, I will stop you.","TWN":"但我還是不能放行。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"옛날 나유카 가문 사람들은 큰 뱀을 막겠다는 일념 하나로 화살을 쏴서 하늘의 별을 떨어뜨렸다고 하죠.","JPN":"かつて奈由香家の人々は大蛇を仕留める一心で矢を放ち、\\n天の星を落としたそうです。","ENG":"In the old days, the Nayukas shot down a star only with the fierce determination to stop the Giant Snake.","TWN":"我曾經聽說過，以前南裕夏家族只因為決心要阻止大蛇，而拼命射箭，射到連天上星星都被射下來。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"가문의 맥이 끊긴 말예인 당신에게도 그 자취가 남아 있나 보군요.","JPN":"家系の血筋が途絶えたとはいえ、末裔のあなたにもその名残が残っているようですね。","ENG":"I see you still have that determination in your blood, even after your family’s fall.","TWN":"你身為這個家族的末代子孫，看來也有遺傳到堅持的DNA。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"칭찬 고마워. 그런 얘기를 들으니까 어깨가 무겁네.","JPN":"褒めてくれてありがとう。そんな話を聞くと荷が重くなるよ。","ENG":"Thank you for the big compliment. To hear that, I feel burdened with responsibility.","TWN":"謝謝誇獎。聽到那些話，怎麼覺得肩膀有點重？！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하지만 칭찬을 듣는다고 해서 마음이 바뀌진 않아.","JPN":"それでも僕の気持ちは変わらない。","ENG":"But it won’t change my mind.","TWN":"不過就算你稱讚我，我也不會改變心意的。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"너와 싸우고 싶지 않아. 생각을 바꿔 주면 안 될까?","JPN":"考え直してくれないか？　君とは戦いたくないんだ。","ENG":"I don’t want to fight you. Could you please change your mind?","TWN":"我不想和你打起來，不如你退一步吧？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"어째서 공은 저를 막는 겁니까? 언니를 도망치게 해서 뭘 어쩔 셈인가요?","JPN":"なぜ私を止めるのですか？　姉上を逃がしてどうするおつもりですか？","ENG":"Why do you stop me? Why would you let my sister run away?","TWN":"爲什麼要攔著我？讓姊姊逃掉後，你想要做什麼？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"너야말로, 당주 자릴 차지하는 게 그렇게 중요한 일이야?","JPN":"君こそ、当主の座を得ることがそこまで重要なこと？","ENG":"Why do you care to be the family leader? Why is it so important to you?","TWN":"我倒想問問你，對你而言，當上堂主有那麼重要嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"자매끼리 경쟁하는 게 대체 무슨 의미가 있어?","JPN":"姉妹で競い合うことになんの意味があるの？","ENG":"Why would you compete with your own sister?","TWN":"姊妹之間這樣競爭有什麼意義？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이건 단순한 경쟁이 아닙니다.","JPN":"これは単なる競争ではありません。","ENG":"This is not a simple competition.","TWN":"這不只是單純的競爭。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저희가 어떤 기로 앞에 놓여있는지… 당신은 이해하지 못하겠죠.","JPN":"私たちがどんな岐路に立たされているのか……\\nあなたにはわからないでしょう。","ENG":"You have no idea what’s coming towards us...","TWN":"你不懂……我們要面對什麼樣的抉擇。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"확실히 그 말은 맞을지도 모르지만…….","JPN":"確かにそのとおりかもしれないけど……","ENG":"Maybe you’re right...","TWN":"或許你說的沒錯……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치나츠는 오로치의 봉인을 다시 막아낼 방법이 있다고 했어.","JPN":"千夏はオロチの封印が解けるのを阻止する方法があると言ったんだ。","ENG":"But Chinatsu told me she knew how to restore Orochi’s seal.","TWN":"但千夏說有辦法可以再次封印住大蛇。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};